(window.webpackJsonp=window.webpackJsonp||[]).push([[923],{875:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">k</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> mostCompetitive = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums, k</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> stack =[]\\n    stack[<span class=\\"hljs-number\\">0</span>]=<span class=\\"hljs-number\\">-1</span>\\n    <span class=\\"hljs-keyword\\">let</span> len = nums.length;\\n    <span class=\\"hljs-keyword\\">for</span> (<span class=\\"hljs-keyword\\">let</span> i = <span class=\\"hljs-number\\">0</span>; i &lt; len; i++) {\\n        <span class=\\"hljs-comment\\">//\u5f53\u524d\u5143\u7d20\u6bd4\u961f\u5c3e\u5143\u7d20\u5c0f\uff0c\u5c06\u961f\u5c3e\u5143\u7d20\u51fa\u6808</span>\\n        <span class=\\"hljs-comment\\">//\u6b64\u5904\u9700\u8981\u53e6\u5916\u5224\u65ad\u6570\u7ec4\u5269\u4f59\u957f\u5ea6\u591f\u4e0d\u591f\u586b\u6ee1\u6808\uff0c\u4e0d\u7136\u6700\u540e\u7b54\u6848\u957f\u5ea6\u53ef\u80fd\u4f1a\u5c0f\u4e8ek</span>\\n        <span class=\\"hljs-keyword\\">while</span> (nums[i] &lt; stack[stack.length<span class=\\"hljs-number\\">-1</span>] &amp;&amp; k - stack.length + <span class=\\"hljs-number\\">1</span> &lt; len - i) {\\n            stack.pop();\\n        }\\n        <span class=\\"hljs-keyword\\">if</span> (stack.length &lt; k + <span class=\\"hljs-number\\">1</span>) {\\n            stack.push(nums[i]);\\n        }\\n    }\\n\\n    <span class=\\"hljs-comment\\">// let ret = []</span>\\n\\n    <span class=\\"hljs-keyword\\">return</span> stack.slice(<span class=\\"hljs-number\\">1</span>)\\n    <span class=\\"hljs-comment\\">// while (k &gt; 0) {</span>\\n    <span class=\\"hljs-comment\\">//     ret[--k] = stack.pop();</span>\\n    <span class=\\"hljs-comment\\">// }</span>\\n\\n    <span class=\\"hljs-comment\\">// return ret;</span>\\n};\\n\\n\\n\\n</code></pre>\\n"],"titleSlug":"find-the-most-competitive-subsequence","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>nums</code> \u548c\u4e00\u4e2a\u6b63\u6574\u6570 <code>k</code> \uff0c\u8fd4\u56de\u957f\u5ea6\u4e3a <code>k</code> \u4e14\u6700\u5177 <strong>\u7ade\u4e89\u529b</strong> \u7684<em> </em><code>nums</code> \u5b50\u5e8f\u5217\u3002</p>\\n\\n<p>\u6570\u7ec4\u7684\u5b50\u5e8f\u5217\u662f\u4ece\u6570\u7ec4\u4e2d\u5220\u9664\u4e00\u4e9b\u5143\u7d20\uff08\u53ef\u80fd\u4e0d\u5220\u9664\u5143\u7d20\uff09\u5f97\u5230\u7684\u5e8f\u5217\u3002</p>\\n\\n<p>\u5728\u5b50\u5e8f\u5217\xa0<code>a</code> \u548c\u5b50\u5e8f\u5217\xa0<code>b</code> \u7b2c\u4e00\u4e2a\u4e0d\u76f8\u540c\u7684\u4f4d\u7f6e\u4e0a\uff0c\u5982\u679c\xa0<code>a</code>\xa0\u4e2d\u7684\u6570\u5b57\u5c0f\u4e8e <code>b</code> \u4e2d\u5bf9\u5e94\u7684\u6570\u5b57\uff0c\u90a3\u4e48\u6211\u4eec\u79f0\u5b50\u5e8f\u5217 <code>a</code> \u6bd4\u5b50\u5e8f\u5217 <code>b</code>\uff08\u76f8\u540c\u957f\u5ea6\u4e0b\uff09\u66f4\u5177 <strong>\u7ade\u4e89\u529b</strong> \u3002 \u4f8b\u5982\uff0c<code>[1,3,4]</code> \u6bd4 <code>[1,3,5]</code> \u66f4\u5177\u7ade\u4e89\u529b\uff0c\u5728\u7b2c\u4e00\u4e2a\u4e0d\u76f8\u540c\u7684\u4f4d\u7f6e\uff0c\u4e5f\u5c31\u662f\u6700\u540e\u4e00\u4e2a\u4f4d\u7f6e\u4e0a\uff0c\xa0<code>4</code> \u5c0f\u4e8e <code>5</code> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [3,5,2,6], k = 2\\n<strong>\u8f93\u51fa\uff1a</strong>[2,6]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5728\u6240\u6709\u53ef\u80fd\u7684\u5b50\u5e8f\u5217\u96c6\u5408 {[3,5], [3,2], [3,6], [5,2], [5,6], [2,6]} \u4e2d\uff0c[2,6] \u6700\u5177\u7ade\u4e89\u529b\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [2,4,3,3,5,4,9,6], k = 4\\n<strong>\u8f93\u51fa\uff1a</strong>[2,3,3,4]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>0 <= nums[i] <= 10<sup>9</sup></code></li>\\n\\t<li><code>1 <= k <= nums.length</code></li>\\n</ul>\\n","title":"1673. \u627e\u51fa\u6700\u5177\u7ade\u4e89\u529b\u7684\u5b50\u5e8f\u5217","relatedTags":["\u6808","\u5806","\u8d2a\u5fc3\u7b97\u6cd5","\u961f\u5217"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1673"}')}}]);